ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?typename ?benefits WHERE {
  ?t a :Job_Type .
  ?j a :Jobs .
  ?j p:hasJobTypes ?t .
  ?t p:typeName ?typename .
  ?j p:Benefits ?benefits .
} }
  full: { SELECT ?typename ?base_pay_range ?benefits WHERE {
  ?t a :Job_Type .
  ?j a :Jobs .
  ?j p:hasJobTypes ?t .
  ?t p:typeName ?typename .
  ?j p:Base_Pay_Range ?base_pay_range .
  ?j p:Benefits ?benefits .
} }
  component_2: { SELECT ?typename ?base_pay_range WHERE {
  ?t a :Job_Type .
  ?j a :Jobs .
  ?j p:hasJobTypes ?t .
  ?t p:typeName ?typename .
  ?j p:Base_Pay_Range ?base_pay_range .
} }
}

